import { useState } from "react";
import { FaEye, FaEyeSlash } from "react-icons/fa";
import { useRef, useEffect } from "react";



function Register({ setView }) {

  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [closing, setClosing] = useState(false);
  const dropdownRef = useRef();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");
const [showPassword, setShowPassword] = useState(false);
const handleToggle = () => {
  if (closing) return; // 🔥 prevent conflict
  setDropdownOpen((prev) => !prev);
};

useEffect(() => {
  const handleClickOutside = (e) => {
    if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
      if (dropdownOpen) closeDropdown(); // 🔥 IMPORTANT
    }
  };

  document.addEventListener("mousedown", handleClickOutside);

  return () => {
    document.removeEventListener("mousedown", handleClickOutside);
  };
}, [dropdownOpen]);
  const handleRegister = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ name, email, password, role }),
      });

      const data = await res.json();

      if (res.ok) {
        alert("Registered successfully ✅");
        setView("login"); // 🔥 go back to login
      } else {
        alert(data.message);
      }
    } catch {
      alert("Error registering");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">

        <h2>Create Account</h2>

        <button
          className="back-btn"
          onClick={() => setView("home")}
        >
          ← Back to Home
        </button>

        <input
          type="text"
          placeholder="Full Name"
          onChange={(e) => setName(e.target.value)}
        />

        <input
          type="email"
          placeholder="Email"
          onChange={(e) => setEmail(e.target.value)}
        />

        <div className="password-field">
          <input
            type={showPassword ? "text" : "password"}
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <span
            className="toggle-eye"
            onClick={() => setShowPassword(!showPassword)}
          >
            {showPassword ? <FaEyeSlash /> : <FaEye />}
          </span>
        </div>

<div className="custom-select" ref={dropdownRef}>
  <div
    className="select-box"
    onClick={() => setDropdownOpen(!dropdownOpen)}
  >
    {role}
    <span className="arrow">⌄</span>
  </div>

  {dropdownOpen || closing && (
  <div className={`options ${closing ? "fade-out" : "fade-in"}`}>
      {["client", "tasker"].map((item) => (
        <div
          key={item}
          className="option"
          onClick={() => {
            setRole(item);
            closeDropdown();
          }}
        >
          {item}
        </div>
      ))}
    </div>
  )}
</div>

        <button className="login-btn" onClick={handleRegister}>
          Register
        </button>

        <p style={{ marginTop: "10px", fontSize: "14px" }}>
          Already have an account?{" "}
          <span
            style={{ color: "#1B3C53", cursor: "pointer" }}
            onClick={() => setView("login")}
          >
            Login
          </span>
        </p>

      </div>
    </div>
  );
}
export default Register;
